#include <WiFi.h>
#include <HTTPClient.h>
#include <DHT.h>

const char* ssid     = "YOUR_WIFI_NAME";
const char* password = "YOUR_WIFI_PASSWORD";

#define DHTPIN 4
#define DHTTYPE DHT11
DHT dht(DHTPIN, DHTTYPE);

void setup() {
  Serial.begin(115200);
  dht.begin();
  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) {
    delay(500);
    Serial.print(".");
  }
  Serial.println("\nWiFi connected");
}

void loop() {
  float temp = dht.readTemperature();
  float hum  = dht.readHumidity();
  Serial.printf("Temp: %.1f C  Humidity: %.1f %%\n", temp, hum);

  if (WiFi.status() == WL_CONNECTED) {
    HTTPClient http;
    http.begin("https://YOUR_ENDPOINT_HERE"); // <-- replace
    http.addHeader("Content-Type", "application/json");
    String body = "{\"temp\":" + String(temp) + ",\"humidity\":" + String(hum) + "}";
    int code = http.POST(body);
    Serial.printf("POST status: %d\n", code);
    http.end();
  }
  delay(60000); // log every minute
}

#include <WiFi.h>
#include <WebServer.h>

const char* ssid     = "YOUR_WIFI_NAME";
const char* password = "YOUR_WIFI_PASSWORD";

const int ledPin = 2;
WebServer server(80);

void handleRoot() {
  String html = "<h1>ESP32 LED Control</h1>"
                "<p><a href=\"/on\">Turn ON</a></p>"
                "<p><a href=\"/off\">Turn OFF</a></p>";
  server.send(200, "text/html", html);
}

void handleOn() {
  digitalWrite(ledPin, HIGH);
  server.send(200, "text/html", "LED is ON. <a href=\"/\">Back</a>");
}

void handleOff() {
  digitalWrite(ledPin, LOW);
  server.send(200, "text/html", "LED is OFF. <a href=\"/\">Back</a>");
}

void setup() {
  Serial.begin(115200);
  pinMode(ledPin, OUTPUT);

  WiFi.begin(ssid, password);
  while (WiFi.status() != WL_CONNECTED) {
    delay(500);
    Serial.print(".");
  }
  Serial.println();
  Serial.print("Open http://");
  Serial.println(WiFi.localIP());

  server.on("/", handleRoot);
  server.on("/on", handleOn);
  server.on("/off", handleOff);
  server.begin();
}

void loop() {
  server.handleClient();
}
